// Player.js
import React, { useState, useRef, useEffect } from 'react';
import { FaPlay, FaStop } from 'react-icons/fa';

function Player() {
    const [isPlaying, setIsPlaying] = useState(false);
    const [streamUrl] = useState('http://172.232.62.146:8000/radio.mp3'); 
    const [metadata, setMetadata] = useState('CURRENTLY OFF-AIR');
    const audioRef = useRef(null);

    const togglePlayPause = () => {
        if (!streamUrl) {
            console.warn("No valid stream URL available.");
            return;
        }

        if (isPlaying) {
            audioRef.current.pause();
        } else {
            audioRef.current.play();
        }
        setIsPlaying(!isPlaying);
    };

    useEffect(() => {
        if (isPlaying) {
            fetch('http://172.232.62.146:8000/radio.mp3')
                .then(response => response.json())
                .then(data => {
                    setMetadata(data.metadata || 'Unknown Stream');
                })
                .catch(error => {
                    console.error("There was an error fetching the metadata:", error);
                    setMetadata('Error fetching data');
                });
        }
    }, [isPlaying]);

    return (
        <div className="player-wrapper">
            <audio ref={audioRef} src={streamUrl} preload="metadata"></audio>
            <button className="play-btn" onClick={togglePlayPause}>
                { isPlaying ? <FaStop /> : <FaPlay /> }
            </button>
            <p className="metadata-info">{ metadata }</p>
        </div>
    )
}

export default Player;
